package com.agmsolutions.fabrick_test.controller;import com.agmsolutions.fabrick_test.Model.dto.*;import com.agmsolutions.fabrick_test.service.AccountService;import org.junit.jupiter.api.DisplayName;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.webmvc.test.autoconfigure.WebMvcTest;import org.springframework.http.MediaType;import org.springframework.test.context.bean.override.mockito.MockitoBean;import org.springframework.test.web.servlet.MockMvc;import org.springframework.web.client.ResourceAccessException;import tools.jackson.databind.ObjectMapper;import java.math.BigDecimal;import java.time.LocalDate;import java.util.List;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.eq;import static org.mockito.Mockito.mock;import static org.mockito.Mockito.when;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;@WebMvcTest(AccountController.class)public class AccountConrtollerTest {    @Autowired    private MockMvc mockMvc;    @Autowired    private ObjectMapper objectMapper;    @MockitoBean    private AccountService accountService;    private static final Long TEST_ACCOUNT_ID = 14537780L;    @Test    @DisplayName("GET /balance - success 200")    void getBalance_success() throws Exception {        BalanceDto balanceDto = mock(BalanceDto.class);        when(accountService.getBalance(TEST_ACCOUNT_ID)).thenReturn(balanceDto);        mockMvc.perform(get("/api/account/balance").param("accountId", TEST_ACCOUNT_ID.toString()))                .andExpect(status().isOk());    }    @Test    @DisplayName("GET /balance - missing accountId 400")    void getBalance_missingParam() throws Exception {        mockMvc.perform(get("/api/account/balance"))                .andExpect(status().isBadRequest());    }    @Test    @DisplayName("GET /balance - service throws 503")    void getBalance_serviceError() throws Exception {        when(accountService.getBalance(TEST_ACCOUNT_ID)).thenThrow(new ResourceAccessException("Errore chiamata Fabrick"));        mockMvc.perform(get("/api/account/balance").param("accountId", TEST_ACCOUNT_ID.toString()))                .andExpect(status().isServiceUnavailable());    }        @Test    @DisplayName("GET /transactions - success 200")    void getTransactions_success() throws Exception {        when(accountService.getTransactions(any(), any(), any())).thenReturn(List.of(mock(TransactionDto.class)));        mockMvc.perform(get("/api/account/transactions")                        .param("accountId", TEST_ACCOUNT_ID.toString())                        .param("dateStart", "2019-01-01")                        .param("dateEnd", "2019-12-01"))                .andExpect(status().isOk());    }    @Test    @DisplayName("GET /transactions - missing params 400")    void getTransactions_missingParams() throws Exception {        mockMvc.perform(get("/api/account/transactions"))                .andExpect(status().isBadRequest());    }        @Test    @DisplayName("GET /transactions - missing params dates 400")    void getTransactions_missingParamsDates() throws Exception {        mockMvc.perform(get("/api/account/transactions")                .param("accountId", TEST_ACCOUNT_ID.toString()))                .andExpect(status().isBadRequest());    }        @Test    @DisplayName("GET /transactions - wrong params dates format 400")    void getTransactions_wrongDatesFormat() throws Exception {        mockMvc.perform(get("/api/account/transactions")                .param("accountId", TEST_ACCOUNT_ID.toString())                .param("dateStart", "01-01-2019")                .param("dateEnd", "12-01-2019"))                .andExpect(status().isBadRequest());    }    @Test    @DisplayName("GET /transactions - service throws 503")    void getTransactions_serviceError() throws Exception {        when(accountService.getTransactions(any(), any(), any())).thenThrow(new ResourceAccessException("Errore chiamata Fabrick"));        mockMvc.perform(get("/api/account/transactions")                        .param("accountId", TEST_ACCOUNT_ID.toString())                        .param("dateStart", "2019-01-01")                        .param("dateEnd", "2019-12-01"))                .andExpect(status().isServiceUnavailable());    }    @Test    @DisplayName("POST /transfer - success 200")    void createMoneyTransfer_success() throws Exception {        MoneyTransferBodyDto body = MoneyTransferBodyDto.builder()                .creditor(CreditorDto.builder()                        .name("John Doe")                        .account(AccountDto.builder()                                .accountCode("IT23A0336844430152923804660")                                .build())                        .build())                .executionDate(LocalDate.now().plusDays(1))                .description("Payment invoice 75/2017")                .amount(BigDecimal.valueOf(1))                .currency("EUR")                .build();                MoneyTransferResponseDto responseDto = mock(MoneyTransferResponseDto.class);        when(accountService.createMoneyTransfer(eq(TEST_ACCOUNT_ID), any())).thenReturn(responseDto);        mockMvc.perform(post("/api/account/transfer")                        .param("accountId", TEST_ACCOUNT_ID.toString())                        .contentType(MediaType.APPLICATION_JSON)                        .content(objectMapper.writeValueAsString(body)))                .andExpect(status().isOk());    }    @Test    @DisplayName("POST /transfer - body validation fails 400")    void createMoneyTransfer_invalidBody() throws Exception {        mockMvc.perform(post("/api/account/transfer")                        .param("accountId", TEST_ACCOUNT_ID.toString())                        .contentType(MediaType.APPLICATION_JSON)                        .content("{}"))                .andExpect(status().isBadRequest());    }    @Test    @DisplayName("POST /transfer - missing accountId 400")    void createMoneyTransfer_missingAccountId() throws Exception {        MoneyTransferBodyDto body = MoneyTransferBodyDto.builder().build();        mockMvc.perform(post("/api/account/transfer")                        .contentType(MediaType.APPLICATION_JSON)                        .content(objectMapper.writeValueAsString(body)))                .andExpect(status().isBadRequest());    }    @Test    @DisplayName("POST /transfer - service throws 503")    void createMoneyTransfer_serviceError() throws Exception {        MoneyTransferBodyDto body = MoneyTransferBodyDto.builder()                .creditor(CreditorDto.builder()                        .name("John Doe")                        .account(AccountDto.builder()                                .accountCode("IT23A0336844430152923804660")                                .build())                        .build())                .executionDate(LocalDate.now().plusDays(1))                .description("Payment invoice 75/2017")                .amount(BigDecimal.valueOf(1))                .currency("EUR")                .build();                when(accountService.createMoneyTransfer(eq(TEST_ACCOUNT_ID), any())).thenThrow(new ResourceAccessException("Errore chiamata Fabrick"));        mockMvc.perform(post("/api/account/transfer")                        .param("accountId", TEST_ACCOUNT_ID.toString())                        .contentType(MediaType.APPLICATION_JSON)                        .content(objectMapper.writeValueAsString(body)))                .andExpect(status().isServiceUnavailable());    }}